const _AC = { ctx: null };
function ac() {
if (!_AC.ctx) _AC.ctx = new (window.AudioContext || window.webkitAudioContext)();
if (_AC.ctx.state === “suspended”) _AC.ctx.resume();
return _AC.ctx;
}
function playP(w, wr, wn) {
try {
const WF = { ME: 220, WE: 174.6, YOU: 196, THEY: 146.8 };
const WS = { EAST: [0,2,4,7,9], SOUTH: [0,4,7,11,14], WEST: [0,3,5,7,10], NORTH: [0,2,5,9,12] };
const WE = {
SPRING: { a: 0.02, r: 0.3, l: 0.3, t: 1.4 },
SUMMER: { a: 0.08, r: 0.6, l: 0.45, t: 1 },
AUTUMN: { a: 0.15, r: 0.8, l: 0.55, t: 0.75 },
WINTER: { a: 0.3, r: 1.5, l: 0.75, t: 0.5 }
};
const WW = { ME: “triangle”, WE: “sawtooth”, YOU: “sine”, THEY: “square” };
const c = ac();
const f = WF[w];
const sc = WS[wr];
const en = WE[wn];
const now = c.currentTime + 0.05;
const mg = c.createGain();
mg.gain.setValueAtTime(0.25, now);
mg.connect(c.destination);
sc.slice(0, 3).forEach((s, i) => {
const o = c.createOscillator();
const g = c.createGain();
o.connect(g);
g.connect(mg);
o.type = WW[w];
o.frequency.setValueAtTime(f * Math.pow(2, s / 12), now);
const t = now + i * en.l * (1 / en.t);
g.gain.setValueAtTime(0, t);
g.gain.linearRampToValueAtTime(0.12, t + en.a);
g.gain.linearRampToValueAtTime(0, t + en.l + en.r);
o.start(t);
o.stop(t + en.l + en.r + 0.1);
});
} catch (e) {}
}
function sfx(type) {
try {
const c = ac();
const now = c.currentTime + 0.02;
const mk = (f, vol, wv, at, rt, t0 = 0) => {
const o = c.createOscillator();
const g = c.createGain();
o.connect(g);
g.connect(c.destination);
o.type = wv || “sine”;
o.frequency.setValueAtTime(f, now + t0);
g.gain.setValueAtTime(0, now + t0);
g.gain.linearRampToValueAtTime(vol, now + t0 + at);
g.gain.linearRampToValueAtTime(0, now + t0 + at + rt);
o.start(now + t0);
o.stop(now + t0 + at + rt + 0.05);
};
if (type === “select”) { mk(440, 0.05, “sine”, 0.02, 0.12); mk(554, 0.04, “sine”, 0.02, 0.12, 0.06); }
if (type === “move”) mk(330, 0.04, “triangle”, 0.01, 0.1);
if (type === “victory”) [261,329,392,523,659].forEach((f,i) => mk(f, 0.06, “triangle”, 0.01, 0.3, i*0.08));
if (type === “defeat”) [330,294,261,220].forEach((f,i) => mk(f, 0.05, “sawtooth”, 0.02, 0.35, i*0.1));
if (type === “fragment”) [523,659,784,1047].forEach((f,i) => mk(f, 0.06, “sine”, 0.01, 0.25, i*0.07));
if (type === “ok”) { mk(440, 0.04, “sine”, 0.02, 0.1); mk(554, 0.03, “sine”, 0.02, 0.1, 0.05); }
if (type === “fail”) [330,294].forEach((f,i) => mk(f, 0.05, “sawtooth”, 0.02, 0.25, i*0.1));
if (type === “hit”) mk(120, 0.07, “sawtooth”, 0.005, 0.08);
if (type === “story”) [392,494,523].forEach((f,i) => mk(f, 0.03, “sine”, 0.03, 0.35, i*0.15));
} catch (e) {}
}

